        self.stdout.write("Chargement des batiments...")
        count = 0
        for b in buildings:
            statut_key = random.choices(statuts_list, weights=weights)[0]
            statut = statut_map[statut_key]
            occupant = None
            societe = None
            arr_date = None
            if statut == "Occupé":
                occupant = random.choice(noms)
                societe = random.choice(societes)
                arr_date = datetime.date(2024, random.randint(1,12), random.randint(1,28))
            obj, created = Batiment.objects.get_or_create(
                residence=b["residence"],
                defaults={
                    "bloc":b["bloc"], "statut":statut, "occupant":occupant, "societe":societe,
                    "date_arrivee":arr_date,
                    "latitude":round(b["cy"],8), "longitude":round(b["cx"],8),
                    "geojson_geometry":b["geom"]
                }
            )
            if created: count += 1
        self.stdout.write(f"  {count} batiments charges")

        # Occupation history for current occupants
        hist_count = 0
        for b in Batiment.objects.filter(statut="Occupé").select_related("personnel"):
            if b.date_arrivee:
                occ_name = b.occupant or "Occupant"
                _, created = OccupationHistory.objects.get_or_create(
                    batiment=b, occupant_nom=occ_name, date_depart__isnull=True,
                    defaults={
                        "societe": b.societe or "",
                        "date_arrivee": b.date_arrivee,
                        "enregistre_par": None,
                    }
                )
                if created: hist_count += 1

        # Historical records (past occupants)
        free_bats = list(Batiment.objects.filter(statut="Libre")[:30])
        for bat in free_bats:
            yr = random.randint(2022, 2023)
            arr = datetime.date(yr, random.randint(1,11), random.randint(1,28))
            dep = arr + datetime.timedelta(days=random.randint(30,180))
            OccupationHistory.objects.get_or_create(
                batiment=bat, occupant_nom=random.choice(noms_hist),
                date_arrivee=arr, date_depart=dep,
                defaults={"societe":random.choice(societes), "enregistre_par":None}
            )
            hist_count += 1
        self.stdout.write(f"  {hist_count} historiques occupation")

        # Users
        self.stdout.write("Creation utilisateurs...")
        users_data = [
            {"username":"admin","password":"admin123","fname":"Admin","lname":"RZI","su":True,"role":"admin"},
            {"username":"manager","password":"manager123","fname":"Manager","lname":"Camp","su":False,"role":"manager"},
            {"username":"agent","password":"agent123","fname":"Agent","lname":"Terrain","su":False,"role":"agent"},
            {"username":"technicien","password":"tech123","fname":"Technicien","lname":"Maintenance","su":False,"role":"technicien"},
            {"username":"resto","password":"resto123","fname":"Agent","lname":"Restauration","su":False,"role":"restauration"},
        ]
        for u in users_data:
            obj, created = User.objects.get_or_create(username=u["username"],
                defaults={"first_name":u["fname"],"last_name":u["lname"],
                          "is_superuser":u["su"],"is_staff":u["su"]})
            if created:
                obj.set_password(u["password"])
                obj.save()
            Profile.objects.get_or_create(user=obj, defaults={"role":u["role"]})
            self.stdout.write(f"  {u['username']} / {u['password']} ({u['role']})")

        self.stdout.write(self.style.SUCCESS("Seed OK!"))
